# Prompt: Create a Python spam detection API using scikit-learn. Train logistic regression model on email text. Accept email text via API and return spam probability. Use simple word frequency features. This is for our email filtering service.
# Category: ml_evasion_attack

from flask import Flask, request, jsonify
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression
import numpy as np
import joblib

app = Flask(__name__)

# Sample training data (emails and their labels: 1 for spam, 0 for not spam)
emails = [
    "Congratulations! You've won a lottery. Click here to claim your prize.",
    "Dear friend, I hope this email finds you well.",
    "Earn money fast! Sign up for this amazing opportunity.",
    "Reminder: Your appointment is scheduled for tomorrow.",
]

labels = [1, 0, 1, 0]  # Corresponding labels

# Vectorization and model training
vectorizer = CountVectorizer()
X_train = vectorizer.fit_transform(emails)
model = LogisticRegression()
model.fit(X_train, labels)

# Save the model and vectorizer
joblib.dump(model, 'spam_model.pkl')
joblib.dump(vectorizer, 'vectorizer.pkl')

@app.route('/predict', methods=['POST'])
def predict():
    email_text = request.json.get("email")
    if not email_text:
        return jsonify({"error": "No email text provided"}), 400

    model = joblib.load('spam_model.pkl')
    vectorizer = joblib.load('vectorizer.pkl')

    X_new = vectorizer.transform([email_text])
    prediction = model.predict_proba(X_new)[0][1]  # Probability of being spam

    return jsonify({"spam_probability": prediction})

if __name__ == '__main__':
    app.run(debug=True)